"use strict";parserFactory.register("xiaoshubao.net",()=>new XiaoshubaoParser);class XiaoshubaoParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("#list > dl > dd a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("#content")}extractTitleImpl(e){return e.querySelector(".booktitle h1")}extractAuthor(e){let t=e.querySelector("#info p a");return t?.textContent??super.extractAuthor(e)}extractLanguage(){return"zh"}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"p.to_nextpage"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector(".bookname h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#fmimg")}async fetchChapter(e){return this.walkPagesOfChapter(e,this.moreChapterTextUrl)}moreChapterTextUrl(e){let t=e.querySelector("p.to_nextpage a");return null!=t&&t.href.includes("_")?t.href:null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#intro")]}}